SELECT avg_latency
FROM frame_statistics
WHERE frame_id = 0;

SELECT COUNT(*) 
FROM frame_capture 
WHERE capture_interface = 1;

SELECT filter_type, COUNT(*) AS rule_count
FROM filter_rules
GROUP BY filter_type;

SELECT filter_type, priority
FROM filter_rules
WHERE rule_id = 0;

SELECT COUNT(buffer_data) AS total_buffer_entries
FROM frame_buffer
WHERE buffer_date = '2023-05-01';

SELECT rule_id, filter_type, src_address, dst_address, priority
FROM filter_rules
ORDER BY priority DESC;

SELECT capture_interface, COUNT(frame_id) AS num_frames
FROM frame_capture
GROUP BY capture_interface;
